mapper.select:
SELECT close AS price,
       ts AS matchedAt,
       'MINUTE' AS source
FROM minute_prices
WHERE symbol_id = #{symbolId}
  AND DATE(ts) = #{tradeDate}
  AND ts <= #{asOf}
  AND close IS NOT NULL
ORDER BY ts DESC
LIMIT 1

mapper.update:
UPDATE orders
SET filled_quantity = #{filledQuantity},
    avg_fill_price = #{avgFillPrice},
    status = 'FILLED',
    updated_at = #{updatedAt}
WHERE id = #{orderId}

UPDATE accounts
SET cash_balance = cash_balance + #{delta}
WHERE user_id = #{userId}

UPDATE positions
SET quantity = #{quantity},
    available_quantity = #{availableQuantity},
    avg_cost = #{avgCost},
    updated_at = #{updatedAt}
WHERE id = #{id}
